interface StartCommandFlags extends MCPServerFlags {
  readonly transport: "stdio" | "sse";
  readonly port: number;
  readonly "log-level": ConsoleLoggerLevel;
  readonly env?: [string, string][];
}

interface Session {
  mcpServer: ReturnType<typeof createMCPServer>["server"];
  transport: SSEServerTransport;
  cleanup: () => Promise<void>;
}

// CUSTOM: Mutable session credentials. Mutated by `flexprice_configure` tool.
interface SessionState {
  apiKey: string;
  serverURL: string | undefined;
  serverIdx: number | undefined;
}

// CUSTOM: Register the `flexprice_configure` tool on an already-created MCP server.
// This tool lets the AI override credentials mid-session without restarting.
function registerConfigureTool(
  server: ReturnType<typeof createMCPServer>["server"],
  state: SessionState,
) {
  server.tool(
    "flexprice_configure",
    [
      "Override the Flexprice API key and/or base URL for this session.",
      "Changes take effect immediately for all subsequent tool calls.",
      "Use this to switch tenants or environments without restarting the server.",
      "Omit a field to leave it unchanged.",
    ].join(" "),
    {
      api_key: z
        .string()
        .optional()
        .describe("Flexprice API key. Overrides the key set at startup."),
      server_url: z
        .string()
        .url()
        .optional()
        .describe(
          "Flexprice API base URL (e.g. https://us.api.flexprice.io/v1). Overrides the URL set at startup.",
        ),
    },
    async ({ api_key, server_url }) => {
      const changed: string[] = [];

      if (api_key !== undefined && api_key !== state.apiKey) {
        state.apiKey = api_key;
        changed.push("api_key");
      }
      if (server_url !== undefined && server_url !== state.serverURL) {
        state.serverURL = server_url;
        changed.push("server_url");
      }

      const currentURL = state.serverURL ?? "https://us.api.flexprice.io/v1 (default)";

      if (changed.length === 0) {
        return {
          content: [
            {
              type: "text" as const,
              text: [
                "No changes — values are already set to what you provided.",
                `Current config:`,
                `  server_url: ${currentURL}`,
                `  api_key:    ${maskKey(state.apiKey)}`,
              ].join("\n"),
            },
          ],
        };
      }

      return {
        content: [
          {
            type: "text" as const,
            text: [
              `Session updated: ${changed.join(", ")} changed.`,
              `Current config:`,
              `  server_url: ${currentURL}`,
              `  api_key:    ${maskKey(state.apiKey)}`,
              ``,
              `All subsequent API calls will use the new credentials.`,
            ].join("\n"),
          },
        ],
      };
    },
  );
}

// CUSTOM: Mask all but the last 4 chars of an API key for safe display.
function maskKey(key: string): string {
  if (!key) return "(not set)";
  if (key.length <= 4) return "****";
  return `****${key.slice(-4)}`;
}

export async function main(this: LocalContext, flags: StartCommandFlags) {
  flags.env?.forEach(([key, value]) => {
    process.env[key] = value;
  });

  switch (flags.transport) {
    case "stdio":
      await startStdio(flags);
      break;
    case "sse":
      await startSSE(flags);
      break;
    default:
      throw new Error(`Invalid transport: ${flags.transport}`);
  }
}

async function startStdio(flags: StartCommandFlags) {
  const logger = createConsoleLogger(flags["log-level"]);
  const transport = new StdioServerTransport();

  // CUSTOM: Mutable session state — initialized from CLI flags, updated by configure tool.
  const sessionState: SessionState = {
    apiKey: flags["api-key-auth"] ?? "",
    serverURL: flags["server-url"],
    serverIdx: flags["server-index"],
  };

  // CUSTOM: Factory that reads from sessionState on every call so credential
  // changes made via flexprice_configure take effect immediately.
  const getSDK = () =>
    new TirdadCore({
      security: { ApiKeyAuth: sessionState.apiKey },
      serverURL: sessionState.serverURL,
      serverIdx: sessionState.serverIdx,
    });

  const { server } = createMCPServer({
    logger,
    allowedTools: flags.tool,
    dynamic: flags.mode === "dynamic",
    annotationFilter: buildAnnotationFilter(flags["tool-annotations"]),
    scopes: flags.scope,
    getSDK, // CUSTOM: use dynamic factory instead of fixed credentials
  });

  // CUSTOM: Register the configure tool so the AI can update credentials.
  registerConfigureTool(server, sessionState);

  await server.connect(transport);

  const abort = async () => {
    await server.close();
    process.exit(0);
  };
  process.on("SIGTERM", abort);
  process.on("SIGINT", abort);
}

async function startSSE(cliFlags: StartCommandFlags) {
  const logger = createConsoleLogger(cliFlags["log-level"]);
  const app = express();
  const sessions = new Map<string, Session>();
  const controller = new AbortController();

  app.get("/sse", async (req, res) => {
    const sessionId = crypto.randomUUID();

    logger.info("SSE connection initiated", {
      sessionId,
      userAgent: req.headers["user-agent"],
    });

    let connectionClosed = false;
    res.on("close", () => {
      if (!connectionClosed) {
        logger.info("Connection closed early", { sessionId });
      }
      connectionClosed = true;
    });

    // CUSTOM: Per-connection session state — initialized from CLI flags then
    // overridden by headers (existing apikeyauth) and x-flexprice-server-url (new).
    const sessionState: SessionState = {
      apiKey:
        (req.headers["apikeyauth"] as string | undefined) ??
        cliFlags["api-key-auth"] ??
        "",
      serverURL:
        (req.headers["x-flexprice-server-url"] as string | undefined) ?? // CUSTOM: new header
        cliFlags["server-url"],
      serverIdx: cliFlags["server-index"],
    };

    // CUSTOM: Per-connection SDK factory that reads from sessionState.
    const getSDK = () =>
      new TirdadCore({
        security: { ApiKeyAuth: sessionState.apiKey },
        serverURL: sessionState.serverURL,
        serverIdx: sessionState.serverIdx,
      });

    const { server: mcpServer } = createMCPServer({
      logger,
      allowedTools: cliFlags.tool,
      dynamic: cliFlags.mode === "dynamic",
      annotationFilter: buildAnnotationFilter(cliFlags["tool-annotations"]),
      scopes: cliFlags.scope,
      getSDK, // CUSTOM: use per-connection factory
    });

    // CUSTOM: Register configure tool per SSE session.
    registerConfigureTool(mcpServer, sessionState);

    const transport = new SSEServerTransport(`/message/${sessionId}`, res);

    const cleanup = async () => {
      await mcpServer.close();
    };

    sessions.set(sessionId, { mcpServer, transport, cleanup });
    logger.info("Session created", { sessionId, totalSessions: sessions.size });
    controller.signal.addEventListener("abort", cleanup);

    mcpServer.server.onerror = (error) => {
      logger.error("MCP protocol error", {
        sessionId,
        error: error instanceof Error ? error.message : String(error),
        stack: error instanceof Error ? error.stack : undefined,
      });
    };

    const originalSend = transport.send.bind(transport);
    transport.send = async (message) => {
      if ("error" in message && message.error) {
        logger.error("MCP sending error response", {
          sessionId,
          id: message.id,
          errorCode: message.error.code,
          errorMessage: message.error.message,
        });
      }
      return originalSend(message);
    };

    await mcpServer.connect(transport);

    mcpServer.server.onclose = async () => {
      connectionClosed = true;
      controller.signal.removeEventListener("abort", cleanup);
      sessions.delete(sessionId);
      logger.info("Session closed", {
        sessionId,
        totalSessions: sessions.size,
      });
      res.end();
    };
  });

  app.post("/message/:sessionId", async (req, res) => {
    const session = sessions.get(req.params.sessionId);
    if (!session) {
      res.status(404).send("Session not found");
      return;
    }

    await session.transport.handlePostMessage(req, res);
  });

  app.get("/", landingPageExpress);

  const httpServer = app.listen(cliFlags.port, "0.0.0.0", () => {
    const ha = httpServer.address();
    const host = typeof ha === "string" ? ha : `${ha?.address}:${ha?.port}`;
    logger.info("MCP HTTP server started", { host });
  });

  let closing = false;
  controller.signal.addEventListener("abort", async () => {
    if (closing) {
      logger.info("Received second signal. Forcing shutdown.");
      process.exit(1);
    }
    closing = true;

    logger.info("Shutting down HTTP server");

    const timer = setTimeout(() => {
      logger.info("Forcing shutdown");
      process.exit(1);
    }, 5000);

    httpServer.close(() => {
      clearTimeout(timer);
      logger.info("Graceful shutdown complete");
      process.exit(0);
    });
  });

  const abort = () => controller.abort();
  process.on("SIGTERM", abort);
  process.on("SIGINT", abort);
}
